using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator = new();

    // --- CalculatePercentage ---

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 10, 0.0)]
    [DataRow(1, 3, 33.333333333333336)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void CalculatePercentage_ResultIsAlwaysInRange()
    {
        var result = _calculator.CalculatePercentage(5, 10);

        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void CalculatePercentage_PerfectScore_ReturnsGreaterThanOrEqual100()
    {
        var result = _calculator.CalculatePercentage(10, 10);

        Assert.IsGreaterThan(99.0, result);
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_PartialScore_IsGreaterThanZero()
    {
        var result = _calculator.CalculatePercentage(1, 10);

        Assert.IsGreaterThan(0.0, result);
        Assert.IsLessThan(100.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroCorrect_ReturnsZero()
    {
        var result = _calculator.CalculatePercentage(0, 10);

        Assert.AreEqual(0.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeTotal_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, -1));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }

    // --- GetGrade boundary tests ---

    [TestMethod]
    [DataRow(100.0, "A")]
    [DataRow(90.0, "A")]
    [DataRow(89.99, "B")]
    [DataRow(80.0, "B")]
    [DataRow(79.99, "C")]
    [DataRow(70.0, "C")]
    [DataRow(69.99, "D")]
    [DataRow(60.0, "D")]
    [DataRow(59.99, "F")]
    [DataRow(0.0, "F")]
    public void GetGrade_AtBoundaries_ReturnsCorrectGrade(double percentage, string expectedGrade)
    {
        var grade = _calculator.GetGrade(percentage);

        Assert.AreEqual(expectedGrade, grade);
    }

    [TestMethod]
    public void GetGrade_HighScore_ResultStartsWithAOrB()
    {
        var grade = _calculator.GetGrade(85.0);

        Assert.Contains(grade, new[] { "A", "B", "C", "D", "F" });
    }

    // --- NormalizeScore ---

    [TestMethod]
    [DataRow(50.0, 100.0, 50.0)]
    [DataRow(25.0, 50.0, 50.0)]
    [DataRow(0.0, 100.0, 0.0)]
    [DataRow(100.0, 100.0, 100.0)]
    public void NormalizeScore_ValidInputs_ReturnsExpected(double rawScore, double maxRaw, double expected)
    {
        var result = _calculator.NormalizeScore(rawScore, maxRaw);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void NormalizeScore_ResultIsAlwaysBetween0And100()
    {
        var result = _calculator.NormalizeScore(45.0, 90.0);

        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void NormalizeScore_RawExceedsMax_CapsAt100()
    {
        var result = _calculator.NormalizeScore(150.0, 100.0);

        Assert.AreEqual(100.0, result);
        Assert.IsLessThan(101.0, result);
    }

    [TestMethod]
    public void NormalizeScore_SmallRaw_IsGreaterThanZero()
    {
        var result = _calculator.NormalizeScore(1.0, 100.0);

        Assert.IsGreaterThan(0.0, result);
        Assert.IsLessThan(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1.0, 100.0));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50.0, 0.0));
    }

    [TestMethod]
    public void NormalizeScore_NegativeMax_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50.0, -10.0));
    }
}

